}
"}

{"path": "/tmp/sv-22422abeb5374f5ea878545af69bf1a6/Components/Pages/Apply.razor", "file_text": "@page "/apply"
@rendermode InteractiveServer
@using sv_22422abeb5374f5ea878545af69bf1a6.Components.JobApplication
@using sv_22422abeb5374f5ea878545af69bf1a6.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="() => AdvanceToStep(2)" />
            break;

        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnBack="() => GoToStep(1)"
                             OnNext="() => AdvanceToStep(3)" />
            break;

        case 3:
            <ReferencesStep References="references"
                            OnBack="() => GoToStep(2)"
                            OnNext="() => AdvanceToStep(4)" />
            break;

        case 4:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="val => coverLetter = val"
                             OnBack="() => GoToStep(3)"
                             OnNext="() => AdvanceToStep(5)" />
            break;

        case 5:
            <ReviewStep PersonalInfo="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        IsSubmitting="isSubmitting"
                        SubmittedId="submittedId"
                        OnBack="() => GoToStep(4)"
                        OnSubmit="SubmitApplication"
                        OnEditStep="GoToStep" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = [];
    private bool isSubmitting;
    private int? submittedId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void AdvanceToStep(int step)
    {
        completedSteps.Add(currentStep);
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter);

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
"}

